sys_script_include.script:
var TAMUtils = Class.create();
TAMUtils.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {
	/**
	 * getTableInfomation Retrieve required field values from 
	 * target table by record sys_id
	 * 
	 * @author GEM/Quynhttn - 15.05.2026
	 * @returns {string|null} JSON string containing field values 
	 * or null when validation fails
	 */
	getTableInfomation: function() {
		// Get value from parameter for client script (TAM_Checkin Candidate Auto Populate)
		var tableName = this.getParameter('sysparm_table_name');
		var fieldReturn = this.getParameter('sysparm_field_return');
		var recordId = this.getParameter('sysparm_record_id');

		// Check empty of parameter 
		if (!tableName || !fieldReturn || !recordId) {
			return null;
		}

		// GlideRecord of target table 
		var grTable = new GlideRecord(tableName);
		var result = {};

		// Get field value of target table
		if(grTable.get(recordId)) {
			var fieldReturnArray = fieldReturn.split(',');
			for (var i = 0; i < fieldReturnArray.length; i++) {
				var fieldName = fieldReturnArray[i];
				result[fieldName] = grTable.getValue(fieldName);
			}
		}

		//Validate return object
		var checkValidate = Object.keys(result).length;
		if (checkValidate > 0) {
			return JSON.stringify(result);
		}
		return null;
	},
    type: 'TAMUtils'
});
